// Filter: Status = 'Email 1 Sent' (or simulated) AND 3+ days elapsed.
const results = [];
for (const item of $input.all()) {
  const status = (item.json.Status || '').trim();
  if (status !== 'Email 1 Sent' && status !== 'Email 1 Sent (Simulated)') continue;
  const sentAt = item.json['Email 1 Sent At'] || item.json.email1SentAt;
  if (sentAt && (new Date() - new Date(sentAt)) >= 3 * 24 * 60 * 60 * 1000) {
    results.push({ json: item.json });
  }
}
return results;

const threads = $input.all();
const leads = $('Filter: 3+ Days Passed').all();
const myEmail = 'kspandian32@gmail.com';

return threads.map((item, idx) => {
  const thread = item.json;
  const lead = leads[idx] ? leads[idx].json : {};
  const messages = thread.messages || [];

  // A REAL reply MUST be from someone else
  const externalMessages = messages.filter(m => {
    const from = (m.From || m.from || '').toLowerCase();
    return !from.includes(myEmail.toLowerCase());
  });

  const hasRealReply = externalMessages.length > 0;

  // Get the last message from the LEAD, not from me
  const lastLeadMsg = externalMessages.length > 0 ? externalMessages[externalMessages.length - 1] : null;
  const replyBody = lastLeadMsg ? (lastLeadMsg.snippet || lastLeadMsg.text || '').toLowerCase() : '';

  const unsubKeywords = ['unsubscribe', 'remove me', 'stop emailing', 'opt out'];
  const isUnsubscribe = unsubKeywords.some(kw => replyBody.includes(kw));

  return { 
    json: { 
      ...lead, 
      _thread: thread, 
      hasRealReply, 
      isUnsubscribe, 
      isActionable: hasRealReply || isUnsubscribe 
    } 
  };
});

// Check for bounce signals in reply body
return $input.all().map(item => {
  const replyBody = (item.json.replyBody || '').toLowerCase();
  const bounceSignals = ['undeliverable', 'delivery failed', 'delivery status notification', 'returned mail', 'recipient address rejected', 'user unknown', 'no such user', 'mailbox full', 'address not found', 'does not exist'];
  const matchedSignal = bounceSignals.find(s => replyBody.includes(s));
  return { json: { ...item.json, isBounce: !!matchedSignal, bounceSignal: matchedSignal || null } };
});

const results = [];
const aiItems = $input.all();
const leadItems = $('Bounce Detection').all();
for (let i = 0; i < aiItems.length; i++) {
  const ai = aiItems[i].json;
  const lead = leadItems[i] ? leadItems[i].json : {};
  if (lead.isBounce) continue;
  let intentData = { intent: 'NOT_INTERESTED', summary: '', confidence: 0 };
  try {
    const content = ai.message?.content || ai.choices?.[0]?.message?.content || '{}';
    const clean = String(content).replace(/```json\n?/g,'').replace(/```/g,'').trim();
    const parsed = JSON.parse(clean);
    intentData.intent = parsed.intent || 'NOT_INTERESTED';
    intentData.summary = parsed.summary || '';
    intentData.confidence = parsed.confidence || 0;
  } catch (e) {}
  results.push({
    json: {
      ...lead,
      intent: intentData.intent,
      summary: intentData.summary,
      confidence: intentData.confidence,
      'AI Summary': intentData.summary,
      'Replied At': new Date().toISOString()
    }
  });
}
return results;

